base_dir = Path(r'E:\github\claude-dotfiles\skills\ascii-align\testcases\新增資料夾\.doc')
source_file = Path(r'E:\github\claude-dotfiles\skills\ascii-align\testcases\Ascii_sample_2026-04-15.md')

# 1. 讀取原始檔
content = source_file.read_text(encoding='utf-8')

# 2. 切割 Sample
# 這裡使用正則表達式尋找 ## Sample XXX 到下一個 ## Sample 或是檔案結尾
sections = re.split(r'\n(?=## Sample \d+)', content)

count = 0
for sec in sections:
    match = re.search(r'## Sample (\d+)', sec)
    if match:
        sid = match.group(1)
        # 匹配映射 (補齊三位數，如 1 -> 001)
        lookup_sid = sid.zfill(3)
        
        if lookup_sid in mapping:
            target_folder = base_dir / mapping[lookup_sid]
            if not target_folder.exists():
                target_folder.mkdir(parents=True)
            
            # 確保內容包含到 --- 分隔符號 (如果有)
            # 重新清理格式，只保留到 --- 之前，或是包含 --- 之後的內容
            file_content = sec.strip() + '\n\n---\n'
            
            (target_folder / f'sample_{lookup_sid}.md').write_text(file_content, encoding='utf-8')
            count += 1

print(f'Successfully re-established {count} samples.')
